#!/usr/bin/env python3
"""
MKT Original — Nahum chapters 1–3 (ch 1:3 already done; skip via merge)
Run: python3 scripts/zc-original-nahum-1-3-full.py

Key translation decisions:
- 1:2 qanna = jealous (covenantal jealousy, not petty); noqem = avenger (cognate of naqam, blood-vengeance); ba&apos;al chemah = lord of wrath
- 1:3 erech apayim = slow to anger (lit. long of nose; the nose was the seat of anger in Hebrew physiology)
  nakeh lo yenakeh = the infinitive absolute + finite verb construction = &quot;will by no means leave unpunished&quot; — emphatic double negative
- 1:7 chasay bo = those who take refuge in him (hayah le-machaseh = covenantal shelter)
- 1:15 mevasser = herald (same root as LXX euangelizomenos = evangelist/one who gospels)
- 2:11 mearat arayot = lion&apos;s den; the lion = the royal/imperial metaphor for Nineveh/Assyria
- 3:1 ir damim = city of blood (plural, intensive)
- 3:4 zanunei = prostitutions; kishufim = sorceries (the city as seductive enchantress)
- 3:8 No-amon = Thebes (sacked by Assyria 663 BCE — the comparison is Nineveh&apos;s own logic turned against it)
"""

import json
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NAHUM = {
    "1": {
        "1": "<p><strong>massa Nineveh, sefer chazot Nachum ha-Elqoshi</strong> — &quot;The burden of Nineveh; the book of the vision of Nahum the Elkoshite.&quot; <em>Massa</em> (burden, oracle) is the standard heading for oracles of judgment — what is lifted up and carried. It is the word of the message and the weight of judgment simultaneously. <em>Sefer chazot</em> (book of the vision) is unusual — most prophetic books are not called &quot;books&quot; within themselves. Nahum identifies what follows as a written, documented vision, not an oral proclamation. Nineveh, the capital of Assyria, is the explicit target from the first word.</p>",
        "2": "<p><strong>El qanna unoqem YHWH</strong> — &quot;A jealous and avenging God is YHWH.&quot; The three-fold <em>noqem</em> (avenger) in vv. 2-3 establishes the character of the God who will act against Nineveh: jealous (<em>qanna</em>, the covenant-possessiveness that will not share his people with any rival), avenging, and lord of wrath (<em>ba&apos;al chemah</em>). This is not emotional volatility but covenantal justice — the same character that in Exod 34:6-7 is simultaneously &quot;abounding in steadfast love&quot; and &quot;will by no means leave the guilty unpunished.&quot; Nahum picks up the second half of that formula and unpacks it against Nineveh.</p>",
        "4": "<p><strong>go&apos;er ba-yam va-yavshehu</strong> — &quot;He rebukes the sea and makes it dry.&quot; The theophanic display of divine power over creation: the sea dried at YHWH&apos;s rebuke (<em>ga&apos;ar</em>), Bashan and Carmel wither, the flower of Lebanon fades. These are the most fertile and productive regions of Israel&apos;s world — YHWH&apos;s rebuke reaches the most verdant places. The sea-drying invokes the Exodus (Exod 14) and the Jordan-crossing (Josh 3) — YHWH&apos;s power to dry the sea is established history, not mythology.</p>",
        "5": "<p><strong>harim ra&apos;ashu mimenu</strong> — &quot;The mountains quake before him.&quot; The cosmic shaking continues: hills melt, the earth lifts up (or is heaved up), the world and all its inhabitants. The language is theophanic (compare Sinai in Exod 19; Ps 68; Hab 3) — the arrival of YHWH produces cosmic disruption. Against this backdrop, Nineveh&apos;s formidable military power is relativized: what chance does the empire have against the one at whose footfall mountains tremble?</p>",
        "6": "<p><strong>lifnei za&apos;amo mi ya&apos;amod</strong> — &quot;Who can stand before his indignation?&quot; The rhetorical question expects the answer &quot;no one.&quot; <em>Za&apos;am</em> (indignation, fierce displeasure — stronger than anger) and <em>charon apo</em> (burning of his anger) describe intensity; <em>nitzkah chemato ka-esh</strong> (his wrath poured out like fire) describes the manner. The rocks are shattered before him — not gradually but in the moment of theophanic arrival. Nahum answers Nineveh&apos;s implicit taunt (&quot;who can stand against us?&quot;) with the counter-question that the only One who matters has already answered.</p>",
        "7": "<p><strong>tov YHWH le-ma&apos;oz be-yom tzara</strong> — &quot;YHWH is good, a stronghold (<em>ma&apos;oz</em>) in the day of trouble.&quot; The pivot within the theophany: the same God whose wrath melts mountains is simultaneously a refuge for those who trust him. <em>Chasay bo</em> (those who take refuge in him) identifies the category of the protected — those who have entered into covenantal shelter. This is the theological center of the book: YHWH&apos;s power that destroys his enemies is the same power that protects his people. One attribute does not limit the other; both flow from the same holiness.</p>",
        "8": "<p><strong>uveshitfah over kalah ya&apos;aseh meqomah</strong> — &quot;He will make a complete end of its place with an overflowing flood.&quot; The flood (<em>shitfah over</em>) is the instrument of Nineveh&apos;s end — historically, the city&apos;s walls were breached when the Tigris flooded and weakened them (2:6 will develop this). &quot;Darkness (<em>choshekh</em>) pursues his enemies&quot; — the darkness that YHWH deploys against enemies in Exodus (plague of darkness) becomes the instrument of pursuit. The end is total (<em>kalah</em> = completion, annihilation).</p>",
        "9": "<p><strong>ma techa&apos;shevun el-YHWH</strong> — &quot;What do you plot against YHWH?&quot; The oracle turns to address the one plotting against YHWH (Sennacherib? The Assyrian empire generally?). The assurance: &quot;He will make a complete end; trouble will not rise up a second time.&quot; Nineveh will fall once and never recover — the judgment will not need to be repeated because it will be comprehensive. The question &quot;What do you plot?&quot; underscores the futility of strategizing against YHWH.</p>",
        "10": "<p><strong>ki ad sirim sevukhim</strong> — &quot;For like entangled thorns they are drunk; they are consumed like fully dry stubble.&quot; The similes depict both vulnerability and flammability: entangled thorns cannot move and are easily burned; drunk men cannot fight. The military might of Assyria, which seemed impenetrable, is reframed as combustible material awaiting the spark. The image of interlocking thorns may also suggest internal chaos — the empire entangling itself.</p>",
        "11": "<p><strong>mimech yatza choshev al-YHWH ra&apos;ah</strong> — &quot;From you has gone out one who plots evil against YHWH, a worthless counselor (<em>yo&apos;etz beliya&apos;al</em>).&quot; The direct address to Nineveh: from this city came the one who counseled wickedness against YHWH. The identity is probably Sennacherib, whose campaign against Jerusalem (701 BCE) was experienced as an assault on YHWH himself (cf. Isa 37). The counselor of worthlessness is the antithesis of the divine Counselor (<em>Yo&apos;etz</em>) of Isaiah 9.</p>",
        "12": "<p><strong>koh amar YHWH im shlemim</strong> — &quot;Thus says YHWH: Though they are at full strength and many, even so they will be cut off and pass away.&quot; The oracle to Judah pivots: though I have afflicted you (<em>inniticha</em>), I will afflict you no more. The Assyrian affliction of Judah was within YHWH&apos;s purposes; but it is now over. The same YHWH who used Assyria as his rod (Isa 10:5) now snaps the rod.</p>",
        "13": "<p><strong>ve-ata eshbor motehu me-alayikh</strong> — &quot;And now I will break his yoke from off you and burst your bonds apart.&quot; The <em>ol</em> (yoke) and <em>moser</em> (bonds) are the standard images of imperial subjugation. The breaking of the yoke by YHWH rather than by military resistance is the key: Judah&apos;s liberation is not self-achieved. The same language recurs in Jeremiah and Isaiah for the messianic liberation.</p>",
        "14": "<p><strong>ve-tziva alecha YHWH lo yizara mish-shimkha od</strong> — &quot;YHWH has given commandment about you: your name shall be perpetuated no more.&quot; The command against the Assyrian king (or Nineveh): the divine name (<em>shem</em>) will be cut off. The temple idols (<em>pesel</em> and <em>massekah</em>, carved image and cast image) will be cut off from their place. The king of Assyria who claimed divine descent and whose name was the axis of imperial ideology will have his name erased. &quot;I will make your grave, for you are vile (<em>taqal</em>).&quot;</p>",
        "15": "<p><strong>hineh al-heharim raglei mevasser</strong> — &quot;Behold, upon the mountains, the feet of him who brings good tidings (<em>mevasser</em>).&quot; The herald on the mountains proclaiming peace and the good news of Judah&apos;s salvation is the exact image Isaiah 52:7 uses for the servant&apos;s proclamation: <em>mah navu al-heharim raglei mevasser</em> (how beautiful on the mountains are the feet of him who brings good tidings). Both texts use <em>mevasser</em>; both announce <em>shalom</em>. Nahum&apos;s herald announces Nineveh&apos;s fall as Judah&apos;s liberation; Isaiah&apos;s herald announces the eschatological liberation from exile. The call to Judah: &quot;Celebrate your feasts, O Judah; fulfill your vows — for the worthless one shall no more pass through you; he is utterly cut off.&quot;</p>"
    },
    "2": {
        "1": "<p><strong>ala hamefitz lefanayikh</strong> — &quot;The scatterer has come up before your face.&quot; Ch 2 opens with the battle for Nineveh dramatized in present tense. The <em>mefitz</em> (scatterer/disperser) is the attacking nation coming against Nineveh — possibly the Babylonian-Median coalition that destroyed Nineveh in 612 BCE. The ironic command to Nineveh to &quot;man the ramparts, watch the road, brace your loins, collect all your strength&quot; is a taunt — Nineveh, who scattered other nations, now faces a scatterer itself.</p>",
        "2": "<p><strong>ki shav YHWH et-ge&apos;on Yaakov</strong> — &quot;For YHWH is restoring the majesty of Jacob as the majesty of Israel.&quot; The theological grounding for the attack on Nineveh: YHWH is restoring the vine strippers have destroyed. The <em>ge&apos;on Yaakov</em> (majesty/pride of Jacob) is what the Assyrians have emptied (<em>beqequm</em>) and destroyed — YHWH&apos;s restoration of his people is the reason for Nineveh&apos;s judgment.</p>",
        "3": "<p><strong>magen gibboreihu me&apos;adem</strong> — &quot;The shield of his warriors is red; the soldiers are clothed in scarlet.&quot; The battle scene in vivid color: red shields (perhaps painted or reflecting firelight), scarlet uniforms, the flash of chariots like lightning on the day of preparation (<em>yom hekino</em>). The imagery is of an irresistible military force advancing — the very kind of army Assyria had deployed against others, now deployed against Nineveh itself.</p>",
        "4": "<p><strong>be-chuzot yitholalun ha-rekev</strong> — &quot;The chariots race madly through the streets.&quot; The chaos of urban warfare: chariots rushing through the city&apos;s open places (<em>rechov</em>), appearance like torches (<em>lapidim</em>), running like lightning. The city that once sent its war machines across the ancient near east now has those same machines — or their equivalent — turning its own streets into a battlefield.</p>",
        "5": "<p><strong>yizkur addirav</strong> — &quot;He summons his officers.&quot; Nineveh&apos;s commander summons his nobles (<em>addirim</em>); they stumble in their march (<em>yikashelu be-halichatam</em>). The protective covering (<em>masakh</em>) is hastily set up. The distinction between the confident advance of the attacker (vv. 3-4) and the stumbling defense of Nineveh&apos;s commanders (v. 5) enacts the reversal.</p>",
        "6": "<p><strong>sha&apos;arei ha-neharot niftachu</strong> — &quot;The gates of the rivers are opened, and the palace melts away.&quot; This verse likely refers to the actual historical flooding of the Tigris and Khosr rivers that breached Nineveh&apos;s defenses in 612 BCE — ancient sources confirm this. The river-gates (<em>sha&apos;arei ha-neharot</em>) opened by flood water turned the city&apos;s great defensive work into a liability. The palace (<em>heikhal</em>) &quot;melts&quot; (<em>mumag</em>) — dissolves under the assault.</p>",
        "7": "<p><strong>vehutzav gilleta he&apos;eleta</strong> — &quot;It is fixed: she is stripped, she is carried away.&quot; <em>Hutzav</em> (it is fixed, determined, settled) — the decree is already issued. The feminine subject (Nineveh personified) is unveiled (<em>gilleta</em>) and led into exile. Her maidservants groan like doves, beating on their breasts — the mourning gesture of complete devastation. The city that stripped others is itself stripped.</p>",
        "8": "<p><strong>ve-Nineveh kimeve mayim hi</strong> — &quot;Nineveh is like a pool of water throughout her days.&quot; The comparison may describe Nineveh&apos;s population as fluid — always escaping — or her water-based defenses. &quot;Stand! Stand!&quot; the cry goes up, but no one turns back. The city that relied on numbers and loyalty finds both dissolving at the moment of crisis.</p>",
        "9": "<p><strong>buzu kesef buzu zahav</strong> — &quot;Plunder the silver, plunder the gold!&quot; The conquerors are exhorted (or the text describes) the looting of Nineveh&apos;s treasury. <em>Ein qetzeh la-tekunah</em> — &quot;there is no end to the treasure, an abundance of every precious thing.&quot; The irony: Nineveh&apos;s wealth, accumulated through generations of imperial tribute and conquest, is now scattered in a day.</p>",
        "10": "<p><strong>buqah umevuqah umevullaqah</strong> — &quot;Emptiness, void, and waste!&quot; Three rare words in sequence (buqah, mevuqah, mevullaqah — possibly a sound-sequence intentionally mimicking desolation) describe Nineveh&apos;s total destruction. Hearts melt (<em>namas lev</em>), knees knock, anguish in every side, faces all grow pale (<em>pnei kulam qibbtzu farim</em>). The physical symptoms of terror in the survivors.</p>",
        "11": "<p><strong>ayeh me&apos;on arayot</strong> — &quot;Where is the den of the lions?&quot; The lion metaphor for Nineveh and its kings is now deployed in reverse. Assyrian kings hunted lions and used lion imagery extensively in their royal iconography — the lion was the symbol of royal power. Now Nahum asks: where is the lion&apos;s den, the pasture of the lion cubs? The lion that killed prey for his cubs (the Assyrian army feeding its dependent nations) — where is it now?</p>",
        "12": "<p><strong>aryeh toreaf bede gurorav</strong> — &quot;The lion tore enough for his cubs.&quot; The past tense marks the end: the lion used to tear prey and fill his caves with kill, his lair with torn prey. The imperial predator that sustained itself through violence against other nations has been exposed for what it always was — a predator, not a provider. YHWH&apos;s indictment of the empire is its own self-description turned against it.</p>",
        "13": "<p><strong>hineni eleyikh ne&apos;um YHWH tzva&apos;ot</strong> — &quot;Behold, I am against you, declares YHWH of hosts.&quot; The divine self-declaration against Nineveh. Three acts: burning her chariots in smoke, the sword devouring her lion cubs, cutting off her prey from the earth, silencing the voice of her messengers (<em>mal&apos;akheyikh</em>). The last item is significant: Nineveh&apos;s messengers (who carried tribute demands and ultimatums across the empire) will be heard no more. The voice of imperial intimidation is silenced.</p>"
    },
    "3": {
        "1": "<p><strong>hoy ir damim</strong> — &quot;Woe to the bloody city!&quot; <em>Ir damim</em> (city of blood, plural — intensive) is the woe-oracle directed at the city as a whole. Three characteristics: full of lies (<em>kalah sheker</em>), full of plunder (<em>perekh</em>), where the prey never departs. The triple accumulation (blood, deception, violence) names the three modalities of Nineveh&apos;s imperial practice: military slaughter, diplomatic deception, and economic extraction.</p>",
        "2": "<p><strong>qol shot uqol ra&apos;ash ofan</strong> — &quot;The crack of the whip, the rumble of the wheel.&quot; An onomatopoeic battle scene: the sounds of Nineveh&apos;s approaching (or now attacking) army turned against itself — whip cracks, wheel rumble, galloping horses, bouncing chariots (<em>merkavah menateret</em>). The war-machine sounds that once signaled conquest now signal defeat.</p>",
        "3": "<p><strong>parash me&apos;aleh velahav cherev</strong> — &quot;The horseman charges, the flashing sword and glittering spear.&quot; The battle continues: mass casualties, no end to the corpses, they stumble over their dead. The vivid present tense puts the reader in the city during its fall. The city that turned its military power against others now experiences the same sword, the same stumbling over corpses that marked Assyrian conquest campaigns.</p>",
        "4": "<p><strong>merov zanunei zona tovat chen</strong> — &quot;Because of the many prostitutions of the prostitute, the graceful and deadly enchantress.&quot; The metaphor shifts: Nineveh as a prostitute-enchantress (<em>ba&apos;alat kishufim</em>, mistress of sorceries) who seduced nations into alliance and then enslaved them. The selling of nations through her prostitutions (<em>zanuneiha</em>) and families through her sorceries is the language of political-economic exploitation described as sexual commerce. The city&apos;s seductive power over subject nations is named as prostitution.</p>",
        "5": "<p><strong>hineni eleyikh ne&apos;um YHWH tzva&apos;ot</strong> — &quot;Behold, I am against you, declares YHWH of hosts.&quot; The second &quot;I am against you&quot; (cf. 2:13) frames the woe oracle. The punishment fits the crime: as Nineveh shamed nations through her prostitutions, YHWH will lift her skirts over her face (<em>giliti she&apos;ulayikh al-panayikh</em>) and show the nations her nakedness. The humiliation is public — the nations who were once enslaved to her will now see her exposed.</p>",
        "6": "<p><strong>ve-hashlikhothi aleyikh shiqutzim</strong> — &quot;I will throw filth at you and make you vile.&quot; The reversal of Nineveh&apos;s dignity: the city that demanded respect and tribute will be treated as dung (<em>shiqutzim</em>, detestable things) and made into a spectacle. All who look at her will flee from her — the revulsion is universal. The empire that attracted envoys and tribute delegations from across the world will repel all observers.</p>",
        "7": "<p><strong>ve-hayah kol ro&apos;ayikh yiddod mimekh</strong> — &quot;All who see you will recoil from you.&quot; The rhetorical question: &quot;Who will grieve for Nineveh? Where shall I seek comforters for her?&quot; (<em>me-ayan avakesh menachemim lakh</em>). The absence of comforters (<em>menachemim</em>) is the ultimate social isolation — not even sympathy is available. The word <em>menachemim</em> echoes Lamentations 1&apos;s repeated refrain about Jerusalem having no comforter. The poetic justice: Nineveh, who showed no comfort to the nations it destroyed, will find none when destroyed.</p>",
        "8": "<p><strong>hatov mino-amon ha-yoshevet be-yeor</strong> — &quot;Are you better than No-amon (Thebes), which was seated by the Nile?&quot; The rhetorical comparison: Thebes, the great Egyptian city, was sacked by Assyria in 663 BCE. Thebes had the Nile, water on every side, allies in Cush and Egypt and Put and Libya — and she still fell. If Nineveh destroyed Thebes, what makes Nineveh think it is exempt? The empire&apos;s own actions provide the precedent for its own judgment.</p>",
        "9": "<p><strong>Kush atzmatah ve-Mitzrayim</strong> — &quot;Cush was her strength, and Egypt too, without limit.&quot; Thebes had formidable allies: Cush (Nubia), Egypt, Put (Libya), and the Lubim — all part of her defensive coalition. Yet she went into exile (<em>galah galtah</em>), her children were dashed to pieces at the corner of every street, her nobles were divided by lot, her great men were bound in chains. If the city with all these allies could fall, so can Nineveh.</p>",
        "10": "<p><strong>gam hi le-gola halkhah</strong> — &quot;She also went into exile, into captivity.&quot; Thebes&apos; fall is rehearsed: her young children dashed to pieces (<em>rutashu</em>), her nobles (<em>nikhbaddeiha</em>) cast lots for as booty, her great men bound in chains. The parallel between Thebes&apos; fate and Nineveh&apos;s imminent fate is the core of the rhetorical argument: Nineveh did this to others; it will happen to Nineveh.</p>",
        "11": "<p><strong>gam at tishkeri tih&apos;i ne&apos;alamah</strong> — &quot;You also will be drunk; you will be hidden.&quot; The intoxication metaphor for judgment (cf. Jer 25; Hab 2:16) — the cup of YHWH&apos;s wrath makes the nation stagger. &quot;You will seek a refuge from the enemy (<em>meqoz me-oyev</em>).&quot; The city that was the source of terror will desperately seek safety from what it once visited on others.</p>",
        "12": "<p><strong>kol-mibtza&apos;yikh teinim im-bikurim</strong> — &quot;All your fortresses are like fig trees with early figs.&quot; The simile: when they are shaken, the figs fall into the mouth of the eater. Nineveh&apos;s fortifications, which took generations to build, will yield to the conqueror as easily as ripe figs fall from a tree when shaken. The fortress system that seemed impregnable proves as fragile as fruit.</p>",
        "13": "<p><strong>hineh amekh nashim be-qirbekh</strong> — &quot;Your troops are women in your midst.&quot; The taunt: Nineveh&apos;s warriors have become women — the ancient shame-rhetoric for military failure. The gates of your land are wide open to your enemies; fire consumes your gate-bars. The gate-system (the most critical element of ancient urban defense) is consumed, leaving the city exposed.</p>",
        "14": "<p><strong>shevi lakh mayim matzor</strong> — &quot;Draw water for the siege.&quot; Nahum ironically commands Nineveh to prepare for siege: draw water, strengthen your fortifications, go into the clay and tread the mortar, take hold of the brick mold. The defensive preparations are futile — named not as effective strategy but as the desperate futility of a city whose end is already determined.</p>",
        "15": "<p><strong>sham tochalekh esh takhritakh cherev</strong> — &quot;There fire will consume you, the sword will cut you off.&quot; The futility climax: despite all preparations, fire and sword end the city. Then the second ironic taunt: &quot;Multiply yourselves like the locust, multiply like the swarming locust!&quot; The command to multiply is futile — it echoes the locust imagery of Nahum&apos;s day. The word <em>arbeh</em> (locust) dominates vv. 15-17.</p>",
        "16": "<p><strong>hirbeit rokhalayikh mikkokevei hashamayim</strong> — &quot;You increased your merchants more than the stars of heaven.&quot; Nineveh&apos;s commercial empire is described: merchants more than stars. Then: the locust sheds its skin and flies away. The merchant empire is as temporary as the locust — present in overwhelming numbers, then suddenly absent. The commercial infrastructure of the empire vanishes as completely as the locust swarm at dawn.</p>",
        "17": "<p><strong>minzarayikh ke-arbeh</strong> — &quot;Your princes are like locusts, your scribes like swarms of locusts.&quot; The administrative apparatus of empire — princes (<em>minzarim</em>, a rare word; possibly cognate with Assyrian governors) and scribes/officials — is compared to locusts that camp in the hedges on a cold day, then fly off when the sun rises. &quot;No one knows where they are&quot; — the empire&apos;s bureaucracy evaporates when the empire falls. The officials who organized the tribute system scatter as completely as locusts.</p>",
        "18": "<p><strong>namu ro&apos;ayikh melek Ashur</strong> — &quot;Your shepherds are asleep, O king of Assyria; your nobles slumber.&quot; The king is directly addressed for the first time explicitly. His &quot;shepherds&quot; (<em>ro&apos;im</em> = the leaders responsible for the people) are asleep — the image of leaders who have failed in their watchman role. The people are scattered on the mountains with no one to gather them. The shepherd imagery (pastoral care, gathering the flock) inverted: Assyria&apos;s own people are scattered, ungathered, on the mountains.</p>",
        "19": "<p><strong>ein kehavah le-shibbrekha</strong> — &quot;There is no healing of your wound; your injury is fatal (<em>nakhla makkatkha</em>).&quot; The final verdict: no healing, no remedy. All who hear the news of Nineveh&apos;s fall will clap their hands over you — not in grief but in relief and vindication: &quot;For upon whom has not your wickedness passed continually?&quot; The universal experience of Assyrian cruelty becomes the explanation for universal rejoicing at its fall. The book ends not with lament but with the relief of a world released from a predator.</p>"
    }
}

def main():
    existing = load_comm('mkt-original', 'nahum')
    merge_comm(existing, NAHUM)
    save_comm('mkt-original', 'nahum', existing)
    print('Nahum 1-3 mkt-original written.')

if __name__ == '__main__':
    main()
